// Make bright stars stand out more
StelSkyDrawer.setRelativeStarScale(1.5);

// Back to default
StelSkyDrawer.setRelativeStarScale(1.0);

// Make all stars brighter
StelSkyDrawer.setAbsoluteStarScale(1.3);

// Make all stars dimmer
StelSkyDrawer.setAbsoluteStarScale(0.7);

// Strong twinkling effect
StelSkyDrawer.setTwinkleAmount(0.8);

// No twinkling (steady stars)
StelSkyDrawer.setTwinkleAmount(0.0);

if (StelSkyDrawer.getFlagTwinkle()) {
    core.debug("Star twinkling is enabled");
}

// Enable atmospheric twinkling
StelSkyDrawer.setFlagTwinkle(true);

// Disable for steady stars
StelSkyDrawer.setFlagTwinkle(false);

if (StelSkyDrawer.getFlagForcedTwinkle()) {
    core.debug("Forced twinkling is enabled");
}

// Dark rural sky
StelSkyDrawer.setLightPollutionLuminance(0.0002);

// Urban sky
StelSkyDrawer.setLightPollutionLuminance(0.005);

if (StelSkyDrawer.getFlagDrawBigStarHalo()) {
    core.debug("Big star halo enabled");
}

// Show halos around bright stars
StelSkyDrawer.setFlagDrawBigStarHalo(true);

// Disable for cleaner appearance
StelSkyDrawer.setFlagDrawBigStarHalo(false);

if (StelSkyDrawer.getFlagStarSpiky()) {
    core.debug("Stars have diffraction spikes");
}

// Add diffraction spikes to stars
StelSkyDrawer.setFlagStarSpiky(true);

// Round stars
StelSkyDrawer.setFlagStarSpiky(false);

// Read using property (recommended)
var isActive = core.getStelProperty('StelSkyDrawer.flagStarMagnitudeLimit');

// Direct call (also works)
if (StelSkyDrawer.getFlagStarMagnitudeLimit()) {
    core.debug("Star magnitude limit is active");
}

// Show only stars brighter than magnitude 4
StelSkyDrawer.setFlagStarMagnitudeLimit(true);
StelSkyDrawer.setCustomStarMagnitudeLimit(4.0);

// Show all stars based on sky conditions
StelSkyDrawer.setFlagStarMagnitudeLimit(false);

if (StelSkyDrawer.getFlagNebulaMagnitudeLimit()) {
    core.debug("Nebula magnitude limit is active");
}

// Show only bright DSOs
StelSkyDrawer.setFlagNebulaMagnitudeLimit(true);
StelSkyDrawer.setCustomNebulaMagnitudeLimit(6.0);

// Show all DSOs
StelSkyDrawer.setFlagNebulaMagnitudeLimit(false);

if (StelSkyDrawer.getFlagPlanetMagnitudeLimit()) {
    core.debug("Planet magnitude limit is active");
}

// Show only bright planets
StelSkyDrawer.setFlagPlanetMagnitudeLimit(true);
StelSkyDrawer.setCustomPlanetMagnitudeLimit(5.0);

// Show all planets
StelSkyDrawer.setFlagPlanetMagnitudeLimit(false);

// Show only stars visible to the naked eye
StelSkyDrawer.setCustomStarMagnitudeLimit(6.0);
StelSkyDrawer.setFlagStarMagnitudeLimit(true);

// Show telescopic stars
StelSkyDrawer.setCustomStarMagnitudeLimit(12.0);

if (StelSkyDrawer.getFlagLuminanceAdaptation()) {
    core.debug("Eye adaptation is active");
}

// Enable realistic eye adaptation
StelSkyDrawer.setFlagLuminanceAdaptation(true);

// Disable for consistent brightness
StelSkyDrawer.setFlagLuminanceAdaptation(false);

// Lower threshold for earlier black labels
StelSkyDrawer.setDaylightLabelThreshold(200.0);

// Higher threshold
StelSkyDrawer.setDaylightLabelThreshold(300.0);

// Clear, dry air
StelSkyDrawer.setExtinctionCoefficient(0.10);

// Humid, hazy conditions
StelSkyDrawer.setExtinctionCoefficient(0.25);

// Cold winter night
StelSkyDrawer.setAtmosphereTemperature(-10.0);

// Warm summer night
StelSkyDrawer.setAtmosphereTemperature(25.0);

// High pressure system
StelSkyDrawer.setAtmospherePressure(1030.0);

// Low pressure
StelSkyDrawer.setAtmospherePressure(990.0);

if (StelSkyDrawer.getFlagDrawSunAfterAtmosphere()) {
    core.debug("Sun drawn after atmosphere");
}

if (StelSkyDrawer.getFlagEarlySunHalo()) {
    core.debug("Sun halo drawn early");
}

if (StelSkyDrawer.getFlagTfromK()) {
    core.debug("Turbidity derived from extinction");
}

// Very clear sky
StelSkyDrawer.setT(2.0);

// Hazy sky
StelSkyDrawer.setT(6.0);
